import React from 'react';
import './world-map.css';
import BattleMode from '../battle-mode/battle-mode'; // Import the BattleMode component

class Overworld extends React.Component {
  constructor(props) {
    super(props);

    this.state = {
      playerPosition: {
        row: 0,
        col: 0,
      },
      badGuyPosition: {
        row: 5, // Initial bad guy row
        col: 5, // Initial bad guy column
      },
      message: '',
      remainingMoves: 2,
      isBadGuyMoving: false,
    };
  }

  componentDidMount() {
    this.updateMessage();
    window.addEventListener('resize', this.handleResize);
  }

  componentWillUnmount() {
    window.removeEventListener('resize', this.handleResize);
  }

  updateMessage = () => {
    const message = window.innerWidth > window.innerHeight ? 'Landscape' : 'Portrait';
    this.setState({ message });
  };

  handleResize = () => {
    this.updateMessage();
  };

  canMove = (row, col) => {
    const { mapData } = this.props;
    const { remainingMoves } = this.state;
    return mapData[row][col] !== 9 && remainingMoves > 0;
  };
  handleTileTouch = (row, col) => {
    if (this.canMove(row, col)) {
      const { mapData } = this.props;
      const numberInSquare = mapData[row][col];

      console.log(`Number in square: ${numberInSquare}`);

      this.setState((prevState) => ({
        playerPosition: { row, col },
        remainingMoves: prevState.remainingMoves - 1,
      }));
    }
  };

  moveBadGuy = () => {
    const { badGuyPosition } = this.state;
    const newBadGuyPosition = { ...badGuyPosition };

    // Implement your logic to move the bad guy
    // For example, move towards the player's position
    if (newBadGuyPosition.row < this.state.playerPosition.row) {
      newBadGuyPosition.row += 1;
    } else if (newBadGuyPosition.row > this.state.playerPosition.row) {
      newBadGuyPosition.row -= 1;
    }

    if (newBadGuyPosition.col < this.state.playerPosition.col) {
      newBadGuyPosition.col += 1;
    } else if (newBadGuyPosition.col > this.state.playerPosition.col) {
      newBadGuyPosition.col -= 1;
    }

    this.setState({ badGuyPosition: newBadGuyPosition });
  };

  handleBattleClose = () => {
    // Set the bad guy position to null to remove it from the map
    this.setState({
      badGuyPosition: null,
    });
  };

  endTurn = () => {
    this.setState(
      {
        remainingMoves: 2,
        isBadGuyMoving: true,
      },
      () => {
        this.moveBadGuy();
        setTimeout(() => {
          this.setState({ isBadGuyMoving: false });
        }, 1000); // Delay for bad guy movement
      }
    );
  };

  renderGameBoard() {
    const { playerPosition, badGuyPosition, remainingMoves } = this.state;
    const { mapData } = this.props;

    return mapData.map((row, rowIndex) => (
      <div key={`row-${rowIndex}`} className="game-row">
        {row.map((tile, colIndex) => {
          const isPlayerTile = rowIndex === playerPosition.row && colIndex === playerPosition.col;
          const isBadGuyTile = badGuyPosition && rowIndex === badGuyPosition.row && colIndex === badGuyPosition.col;
          const rowDiff = Math.abs(rowIndex - playerPosition.row);
          const colDiff = Math.abs(colIndex - playerPosition.col);
          const isHighlighted = rowDiff <= remainingMoves && colDiff <= remainingMoves;

          return (
            <div
              key={`tile-${rowIndex}-${colIndex}`}
              className={`game-tile ${tile === 9 ? 'non-walkable' : ''} ${
                isPlayerTile ? 'player-icon' : ''
              } ${isBadGuyTile ? 'bad-guy-icon' : ''} ${isHighlighted ? 'highlighted' : ''}`}
              onTouchStart={() => this.handleTileTouch(rowIndex, colIndex)}
            >
              {tile === 0 && <div className="obstacle"></div>}
            </div>
          );
        })}
      </div>
    ));
  }



  render() {
    const { message, isBadGuyMoving, playerPosition, badGuyPosition, isBattleMode } = this.state;

    return (
      <div className="world-map-container">
        <h1>{message}</h1>
        <div className="world-map">
  {this.renderGameBoard()}
  {badGuyPosition && playerPosition.row === badGuyPosition.row && playerPosition.col === badGuyPosition.col && (
    <BattleMode onCloseBattle={this.handleBattleClose} />
  )}
</div>
        <button onClick={this.endTurn} disabled={isBadGuyMoving || isBattleMode}>
          End Turn
        </button>
      </div>
    );







  }

}

export default Overworld;
